import stringfrom agent import *from models.products import *import redebug = Truedef process_view_category(data, context, session):    for view_categoryline in data.xpath("//table[@class='sortable']//a"):         url = view_categoryline.xpath("(.)/@href").string()        name = view_categoryline.xpath("(.)/text()").string()        date = view_categoryline.xpath("(.)/preceding::td[1]//text()").string()        if url and name:           session.queue(Request(url), process_view_product, {'url': url, 'name': name, 'date': date })def process_view_product(data, context, session):    product = Product()    product.category = 'Microphones'    product.name = context['name']     product.url = context['url']    product.ssid = product.name    img = data.xpath("//div[@class='entrywrap']//img[contains(@src,'.jpg')]//@src").string()    if img:       product.properties.append(ProductProperty(type="image" , value = {'src': img}))    review = Review()      review.product = product.name       review.url = product.url       review.ssid = product.ssid        author = data.xpath("//p[@class='date']/a//text()").string()    aurl = data.xpath("//p[@class='date']/a//@href").string()    if author and aurl:       review.authors.append(Person(name = author, profile_url = aurl, ssid = review.ssid))       date = context['date']    if date:       review.date = date    else:       review.date = "N/A"    exc = data.xpath("//div[@class='entrywrap']/p//text()").string(multiple=True)    if exc:       review.properties.append(ReviewProperty(type="excerpt", value = exc ))                                   review.type = 'pro'    product.reviews.append(review)     session.emit(product)def run(context, session):    session.queue(Request('http://recordinghacks.com/reviews/tapeop/'), process_view_category, { } )